
"use client";

import { useState, useEffect } from "react";
import Image from 'next/image';
import Link from 'next/link';
import { UserPlus, Mail, Shield, MoreVertical } from "lucide-react";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Badge } from "@/components/ui/badge";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { User } from "@/utils/storage";
import { getUsersAction } from "@/app/actions/dbActions";
import {
  Home,
  FileText,
  CalendarCheck,
  FlaskConical,
  History,
  Settings,
  Library,
  LogOut,
  Users
} from 'lucide-react';
import { usePathname } from "next/navigation";
import { useAuth } from "@/contexts/AuthContext";
import { addAuditLogAction } from "@/app/actions/dbActions";

const AdminSidebar = () => {
    const { user, logout } = useAuth();
    const pathname = usePathname();

    const handleLogout = async () => {
        if(user) {
            await addAuditLogAction({ userId: user.id, userName: user.name, action: 'logout' });
        }
        logout();
    };

    const sidebarNavItems = [
        { title: 'Dashboard', icon: Home, href: '/dashboard' },
        { title: 'User Management', icon: Users, href: '/admin/users' },
        { title: 'Request Management', icon: FileText, href: '/admin/requests' },
        { title: 'Attendance Report', icon: CalendarCheck, href: '/admin/reports' },
        { title: 'LAB Management', icon: FlaskConical, href: '/admin/labs' },
        { title: 'Library', icon: Library, href: '/admin/library' },
        { title: 'Audit Log', icon: History, href: '/admin/audit' },
        { title: 'System Settings', icon: Settings, href: '/admin/settings' },
    ];

    return (
        <aside className="w-64 bg-white p-5 flex flex-col border-r">
            <div className="text-center mb-6 mt-2">
                <Link href="/profile">
                    <div className="w-16 h-16 rounded-md bg-primary text-white flex items-center justify-center mx-auto mb-3 cursor-pointer">
                        <span className="text-2xl font-bold">{user?.name?.charAt(0) || 'A'}</span>
                    </div>
                </Link>
                <h3 className="font-semibold text-gray-800">Administrator</h3>
                <p className="text-sm text-muted-foreground">{user?.name}</p>
            </div>

            <nav className="flex-grow space-y-2">
                {sidebarNavItems.map((item) => {
                    const isActive = pathname === item.href;
                    return (
                        <Link key={item.title} href={item.href} passHref>
                            <Button
                                variant={isActive ? 'default' : 'ghost'}
                                className={`w-full justify-start gap-3 text-base font-medium ${isActive ? 'text-white' : 'text-gray-600 hover:text-primary hover:bg-primary/5'}`}
                                style={isActive ? { backgroundColor: '#E30613' } : {}}
                            >
                                <item.icon className={`w-5 h-5 ${isActive ? 'text-white' : 'text-gray-400 group-hover:text-primary'}`} />
                                {item.title}
                            </Button>
                        </Link>
                    )
                })}
            </nav>
            
            <div className="mt-auto">
                <Button onClick={handleLogout} variant="ghost" className="w-full justify-start gap-3 text-base font-medium text-red-500 hover:text-red-700 hover:bg-red-50">
                    <LogOut className="w-5 h-5" />
                    Logout
                </Button>
            </div>
        </aside>
    );
}

export default function UserManagementPage() {
    const [users, setUsers] = useState<User[]>([]);

    useEffect(() => {
        const fetchUsers = async () => {
            const userList = await getUsersAction();
            setUsers(userList);
        };
        fetchUsers();
    }, []);

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col">
        <header className="bg-primary shadow-lg sticky top-0 z-20">
            <div className="mx-auto px-8 h-16 flex items-center">
            <Image src="/logo.png" alt="AMA Student Portal" width={150} height={38} priority />
            </div>
        </header>
        <div className="flex flex-1">
            <AdminSidebar />
            <main className="flex-1 p-8 overflow-y-auto">
                <div className="flex justify-between items-center mb-8">
                    <div>
                    <h1 className="text-3xl font-bold text-gray-800">User Management</h1>
                    <p className="text-muted-foreground">Manage staff and student accounts.</p>
                    </div>
                    <Button className="gap-2 bg-primary hover:bg-primary/90 text-white" disabled>
                    <UserPlus className="h-4 w-4" /> Add User (Soon)
                    </Button>
                </div>

                <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4">
                    {users.map((user) => (
                    <Card key={user.id} className="overflow-hidden hover:border-primary/50 transition-colors">
                        <CardHeader className="pb-4">
                        <div className="flex justify-between items-start">
                            <Avatar className="h-12 w-12 border-2 border-primary/10">
                            <AvatarImage src={user.profilePic} />
                            <AvatarFallback>{user.name.charAt(0)}</AvatarFallback>
                            </Avatar>
                            <DropdownMenu>
                            <DropdownMenuTrigger asChild>
                                <Button variant="ghost" size="icon" className="h-8 w-8">
                                <MoreVertical className="h-4 w-4" />
                                </Button>
                            </DropdownMenuTrigger>
                            <DropdownMenuContent align="end">
                                <DropdownMenuItem>Edit Permissions</DropdownMenuItem>
                                <DropdownMenuItem>View Activity</DropdownMenuItem>
                                <DropdownMenuItem className="text-destructive">Deactivate</DropdownMenuItem>
                            </DropdownMenuContent>
                            </DropdownMenu>
                        </div>
                        <CardTitle className="mt-4 text-lg">{user.name}</CardTitle>
                        <CardDescription className="flex items-center gap-1">
                            <Mail className="h-3 w-3" /> {user.email}
                        </CardDescription>
                        </CardHeader>
                        <CardContent>
                        <div className="flex items-center justify-between">
                            <Badge variant={user.role === 'admin' ? 'default' : 'secondary'} className="gap-1">
                            <Shield className="h-3 w-3" /> {user.role}
                            </Badge>
                            <span className="text-xs text-muted-foreground italic capitalize">{user.role}</span>
                        </div>
                        </CardContent>
                    </Card>
                    ))}
                </div>
            </main>
        </div>
    </div>
  );
}
